import React, { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "react-query";
import { leaveAPI } from "../utils/api";
import { useAuth } from "../context/AuthContext";
import LoadingSpinner from "../components/common/LoadingSpinner";
import Modal from "../components/common/Modal";
import { PlusIcon, SparklesIcon } from "@heroicons/react/24/outline";
import toast from "react-hot-toast";
import clsx from "clsx";
const LEAVE_TYPES = ["annual","sick","maternity","paternity","emergency","unpaid","compensatory","study"];
const STATUS_COLOR = { pending:"badge-warning", approved:"badge-success", rejected:"badge-danger", cancelled:"badge-neutral" };
export default function Leave() {
  const { user, isAdmin } = useAuth();
  const qc = useQueryClient();
  const [modalOpen, setModalOpen] = useState(false);
  const [form, setForm] = useState({ leaveType:"annual", startDate:"", endDate:"", reason:"" });
  const { data, isLoading } = useQuery("leaveRequests", () => leaveAPI.getAll({ limit: 50 }).then(r => r.data));
  const { data: balance } = useQuery(["leaveBalance", user?.employeeId], () => leaveAPI.getBalance(user.employeeId).then(r => r.data.data), { enabled: !!user?.employeeId });
  const createMut = useMutation(leaveAPI.create, { onSuccess: () => { toast.success("Leave request submitted"); qc.invalidateQueries("leaveRequests"); setModalOpen(false); }, onError: err => toast.error(err.response?.data?.message || "Failed") });
  const approveMut = useMutation(leaveAPI.approve, { onSuccess: () => { toast.success("Approved"); qc.invalidateQueries("leaveRequests"); } });
  const rejectMut = useMutation(({ id }) => leaveAPI.reject(id, { reason: "Rejected by manager" }), { onSuccess: () => { toast.success("Rejected"); qc.invalidateQueries("leaveRequests"); } });
  if (isLoading) return <LoadingSpinner />;
  const requests = data?.data || [];
  return (
    <div className="space-y-5 animate-in">
      <div className="flex items-center justify-between"><div><h1 className="page-title">Leave Management</h1><p className="text-slate-500 text-sm mt-0.5">{requests.filter(r=>r.status==="pending").length} pending requests</p></div><button onClick={() => setModalOpen(true)} className="btn-primary"><PlusIcon className="w-4 h-4" />Apply for Leave</button></div>
      {balance && <div className="grid grid-cols-3 gap-3">{[["Annual",balance.annual,balance.usedAnnual||0],["Sick",balance.sick,balance.usedSick||0],["Emergency",balance.emergency,0]].map(([type,total,used])=>(<div key={type} className="card"><p className="text-sm font-medium text-slate-700">{type} Leave</p><p className="text-2xl font-bold text-slate-900 mt-1">{total-used}<span className="text-sm text-slate-400 font-normal"> / {total}</span></p><div className="mt-2 h-1.5 bg-slate-100 rounded-full overflow-hidden"><div className="h-full bg-primary-500 rounded-full" style={{width:`${total>0?(used/total)*100:0}%`}} /></div></div>))}</div>}
      <div className="card overflow-x-auto"><table className="w-full"><thead className="border-b border-slate-100"><tr>{(isAdmin()?["Employee","Type","Dates","Days","AI Rec","Status","Actions"]:["Type","Dates","Days","Status"]).map(h=>(<th key={h} className="table-header">{h}</th>))}</tr></thead><tbody>
        {requests.length===0?(<tr><td colSpan={7} className="text-center py-10 text-slate-400">No leave requests</td></tr>):requests.map(req=>(<tr key={req.id} className="table-row">
          {isAdmin()&&<td className="table-cell"><p className="font-medium">{req.employee?.firstName} {req.employee?.lastName}</p></td>}
          <td className="table-cell capitalize">{req.leaveType}</td>
          <td className="table-cell text-xs">{req.startDate} – {req.endDate}</td>
          <td className="table-cell">{req.totalDays}d</td>
          {isAdmin()&&<td className="table-cell">{req.aiRecommendation?<span className={clsx("badge text-xs",req.aiRecommendation==="approve"?"badge-success":"badge-warning")}><SparklesIcon className="w-2.5 h-2.5 inline mr-1"/>{req.aiRecommendation}</span>:"—"}</td>}
          <td className="table-cell"><span className={clsx("badge",STATUS_COLOR[req.status]||"badge-neutral")}>{req.status}</span></td>
          {isAdmin()&&<td className="table-cell">{req.status==="pending"&&<div className="flex gap-2"><button onClick={()=>approveMut.mutate(req.id)} className="text-xs text-emerald-600 hover:underline font-medium">Approve</button><button onClick={()=>rejectMut.mutate({id:req.id})} className="text-xs text-red-500 hover:underline font-medium">Reject</button></div>}</td>}
        </tr>))}
      </tbody></table></div>
      <Modal isOpen={modalOpen} onClose={()=>setModalOpen(false)} title="Apply for Leave" footer={<><button onClick={()=>setModalOpen(false)} className="btn-secondary">Cancel</button><button onClick={()=>createMut.mutate(form)} disabled={createMut.isLoading} className="btn-primary">{createMut.isLoading?"Submitting…":"Submit Request"}</button></>}>
        <div className="space-y-4">
          <div><label className="label">Leave Type</label><select className="input capitalize" value={form.leaveType} onChange={e=>setForm(f=>({...f,leaveType:e.target.value}))}>{LEAVE_TYPES.map(t=>(<option key={t} value={t} className="capitalize">{t}</option>))}</select></div>
          <div className="grid grid-cols-2 gap-3"><div><label className="label">Start Date</label><input type="date" className="input" value={form.startDate} onChange={e=>setForm(f=>({...f,startDate:e.target.value}))} /></div><div><label className="label">End Date</label><input type="date" className="input" value={form.endDate} onChange={e=>setForm(f=>({...f,endDate:e.target.value}))} /></div></div>
          <div><label className="label">Reason</label><textarea rows={3} className="input resize-none" value={form.reason} onChange={e=>setForm(f=>({...f,reason:e.target.value}))} placeholder="Brief reason…" /></div>
        </div>
      </Modal>
    </div>
  );
}
